var SteptracePlugin = class extends Plugin {
  onload() {
    this.registerMarkdownCodeBlockProcessor(
      "steptrace",
      (source, el2, ctx) => {
        let config;
        try {
          config = JSON.parse(source);
        } catch (error) {
          el2.createEl("pre", {
            text: `steptrace: invalid JSON
${error instanceof Error ? error.message : String(error)}`
          });
          return;
        }
        const root = el2.createEl("div");
        const handle = steptrace2.mount(root, config, { createSpeedSlider });
        ctx.addChild(new SteptraceChild(el2, handle));
      }
    );
    this.addCommand({
      id: "reload",
      name: "Reload plugin",
      callback: async () => {
        const id = this.manifest.id;
        await this.app.plugins.disablePlugin(id);
        await this.app.plugins.enablePlugin(id);
        new Notice("steptrace reloaded");
      }
    });
  }
};
module.exports = SteptracePlugin;
